using Dapper;
using Valora.Application.Contracts;
namespace Valora.Infrastructure.Repositories;
public sealed class FormRepository(IDbConnectionFactory f):IFormRepository{ public async Task<dynamic?> GetAsync(Guid id)=>await GetByIdAsync(id); public async Task<dynamic?> GetByIdAsync(Guid id){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT id,name,description,time_min FROM valorapesquisa.forms WHERE id=@id AND is_deleted=false",new{id});} public async Task<IReadOnlyList<dynamic>> GetDimensionsAsync(Guid formId){using var c=f.Create(); return (await c.QueryAsync("SELECT id,name,description,display_order,max_score FROM valorapesquisa.form_dimensions WHERE form_id=@formId ORDER BY display_order",new{formId})).ToList();} public async Task<IReadOnlyList<dynamic>> GetQuestionsAsync(Guid formId){using var c=f.Create(); return (await c.QueryAsync("SELECT id,form_id,dimension_id,text,type,required,COALESCE(max_score,5) max_score,display_order FROM valorapesquisa.questions WHERE form_id=@formId ORDER BY display_order",new{formId})).ToList();} public async Task<IReadOnlyList<dynamic>> GetQuestionOptionsAsync(Guid formId){using var c=f.Create(); return (await c.QueryAsync("SELECT qo.id,qo.question_id,qo.text,qo.score,qo.display_order FROM valorapesquisa.question_options qo JOIN valorapesquisa.questions q ON q.id=qo.question_id WHERE q.form_id=@formId ORDER BY qo.display_order",new{formId})).ToList();}}
